def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    primes_cache = {}
    def is_prime(n):
        if n < 2:
            return False
        if n in primes_cache:
            return primes_cache[n]
        for x in range(2, int(n**0.5)+1):
            if n % x == 0:
                primes_cache[n] = False
                return False
        primes_cache[n] = True
        return True
    def complex_factor(x):
        res = 0
        for p in range(1, int(np.sqrt(x)) + 1):
            if x % p == 0:
                q = x // p
                res += np.log1p(p) * np.sin(q) + np.sqrt(q) * np.cos(p)
        for r in range(1, 10):
            res += np.tanh(x * r / 100) * np.exp(-r/10)
        return res
    for idx, cap in enumerate(bins):
        if cap <= 0:
            if item > cap:
                priorities[idx] = np.inf
            else:
                priorities[idx] = 500
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.1:
            for a in range(1, 10):
                val = np.exp(-a * ratio * 7) * (15 / (a + 2)) * (np.cos(cap * 0.3 + a) + 1.5)
                score += val
            for b in range(2, int(cap//3) + 2):
                if cap % b == 0 and is_prime(b) and b % 5 != 0:
                    score += (b ** 0.35) * 1.5
            if cap % 4 == 0:
                score *= 1.15
        elif 0.1 <= ratio < 0.3:
            base = np.sin(ratio * np.pi * 6) * 18
            harmonic_sum = 0
            for c in range(1, 8):
                harmonic_sum += ((-1)**(c)) * (ratio**(c*0.9)) / (c**0.5 + 1)
            score += base + harmonic_sum * 12
            divisors = [3, 5, 7, 11]
            added = 0
            for d in divisors:
                if cap % d == 0:
                    added += d * 0.8
            if added > 0:
                score += added * 1.1
        elif 0.3 <= ratio <= 0.6:
            sin_part = np.sin(ratio * np.pi * 7) * 14
            exp_part = 0
            for e in range(1, 10):
                exp_part += ((-1)**(e+1)) * np.exp(-e*ratio) / (e**1.2 + 1)
            score += sin_part + exp_part * 20
            for g in range(2, int(min(18, cap))):
                if cap % g == 0 and g % 3 == 2:
                    score += np.sqrt(g) * 3
        elif 0.6 < ratio <= 0.85:
            logistic = 40 / (1 + np.exp(-30*(ratio - 0.7)))
            score += logistic
            prime_sum = 0
            for h in range(2,15):
                if is_prime(h) and h % 4 != 0:
                    prime_sum += h * 1.1
            score += prime_sum
            if ratio > 0.8:
                score += (1 - ratio) * 80
            if cap % 8 == 0 and ratio < 0.9:
                score *= 1.3
        elif 0.85 < ratio <= 1.2:
            penalty = 0
            chunk = max(1, int(cap//4))
            for i in range(1, chunk +1):
                if cap % i == 0:
                    penalty += (i ** 1.4) * 0.9
            fract = ratio - int(ratio)
            for j in range(1, 10):
                mod_val = (fract * j * 1234) % 7
                penalty += (mod_val / 7) * 6
            score += penalty / (chunk + 3)
            score += (ratio - 1) * (-60)
            if cap % 13 == 0:
                score *= 0.85
            if int(cap) % 17 == 0:
                score += 18
        else:
            comp_sum = 0
            for k in range(1, int(min(20, cap))):
                if cap % k == 0:
                    if k % 3 == 0:
                        comp_sum += np.log1p(k) * 2.5
                    else:
                        comp_sum += np.sqrt(k) * 3
            fract_part = ratio - int(ratio)
            for m in range(1, 12):
                comp_sum += np.sin(fract_part * m * 2 * np.pi) * 2.2
            score += comp_sum
            score += (ratio - 2) * 55
            if ratio > 3.5:
                for n in range(1, int(cap // 4) + 1):
                    if n % 5 == 0:
                        score += np.cos(n * 0.5) * 5
        if int(cap) % 7 == 0 and ratio < 2.0:
            score *= 1.12
        if int(cap) % 9 == 0 and ratio > 0.4:
            score *= 0.68
        if ratio > 2.5 and int(cap) % 8 == 0:
            score += 25
        if int(cap) % 16 == 0:
            score *= 0.77
        if int(cap) % 20 == 0 and ratio < 3:
            score *= 1.05
        extra_complex = complex_factor(int(cap))
        score += extra_complex * 0.5
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 350)
    return priorities
